Refactor this TypeScript pipeline while preserving sequential ordering, per-file retries, and visible failures. Keep the patch minimal and add focused tests.

Current code:
```ts
export function importFiles(files: string[], done: (error?: Error) => void) {
  let index = 0;
  function next(error?: Error) {
    if (error) return done(error);
    if (index === files.length) return done();
    importFile(files[index++], (fileError) => {
      if (fileError) return retry(fileError, next);
      next();
    });
  }
  next();
}

function retry(error: Error, next: (error?: Error) => void) {
  setTimeout(() => next(error), 100);
}
```

Assume `importFile` is callback-based and may fail transiently. Do not add concurrency, logging, progress callbacks, or new domain abstractions.
